#include <vector>
#include <iostream>

using namespace std;

struct DNA_Sample
{
    string name;
    int length;
    char *bp1;
    char *bp2;
};

vector<DNA_Sample> catalog;

bool checkCorrectBasePair(char b1, char b2)
{

    char lcb1 = 'x';
    char lcb2 = 'x';

    if (b1 == 'a' || b1 == 'A')
        lcb1 = 'A';
    if (b1 == 't' || b1 == 'T')
        lcb1 = 'T';
    if (b1 == 'g' || b1 == 'G')
        lcb1 = 'G';
    if (b1 == 'c' || b1 == 'C')
        lcb1 = 'C';

    if (b2 == 'a' || b2 == 'A')
        lcb2 = 'A';
    if (b2 == 't' || b2 == 'T')
        lcb2 = 'T';
    if (b2 == 'g' || b2 == 'G')
        lcb2 = 'G';
    if (b2 == 'c' || b2 == 'C')
        lcb2 = 'C';

    if (b1 == ' ' || b1 == ' ' || b1 == '\0' || b2 == '\0')
    {
        return true; // ignore padding
    }

    if (lcb1 == 'x' || lcb2 == 'x')
    {
        cout << " invalid base " << b1 << " - " << b2 << endl;
        return false;
    }

    string basePair = "";

    basePair.push_back(lcb1);
    basePair.push_back(lcb2);

    if (basePair != "AT" && basePair != "TA" && basePair != "GC" && basePair != "CG")
    {
        cout << "invalid base pair " << basePair << endl;
        return false;
    }

    return true;
}

vector<float> matchCheck(DNA_Sample sample, int padding)
{
    vector<float> results(catalog.size(), 0.0f);

    for (int j = 0; j < catalog.size(); j++)
    {
        int matches = 0;
        for (int i = padding; i < sample.length; i++)
        {

            int bp1Matchs = sample.bp1[i] - catalog[j].bp1[i];
            int bp2Matchs = sample.bp2[i] - catalog[j].bp2[i];
            int result = bp1Matchs - bp2Matchs;

            if (result == 0 && checkCorrectBasePair(sample.bp1[i], sample.bp2[i]))
            {
                matches++;
            }

            results[j] = (float)matches / (float)(sample.length - padding);
        }
    }

    return results;
}

void populateCatalog()
{

    int len = 100;

    DNA_Sample sample1 = {
        "species 1",
        10000,
        (char *)"",
        (char *)"",
    };
    DNA_Sample sample2 = {
        "species 2",
        10000,
        (char *)"",
        (char *)"",
    };
    DNA_Sample sample3 = {
        "species 3",
        10000,
        (char *)"",
        (char *)"",
    };
    DNA_Sample sample4 = {
        "species 4",
        10000,
        (char *)"",
        (char *)"",
    };
    DNA_Sample sample5 = {
        "species 5",
        10000,
        (char *)"",
        (char *)"",
    };
    catalog.push_back(sample1);
    catalog.push_back(sample2);
    catalog.push_back(sample3);
    catalog.push_back(sample4);
    catalog.push_back(sample5);

    // randomly generated samples
    int rgen = 200;
    srand(time(NULL));

    for (int i = 0; i < rgen; i++)
    {
        string base1 = "";
        string base2 = "";

        for (int i = 0; i < 9999; i++)
        {
            int rand_num = (int)(rand() % 4);

            if (rand_num == 0)
            {
                base1 += 'A';
                base2 += 'T';
            }
            else if (rand_num == 1)
            {
                base1 += 'T';
                base2 += 'A';
            }
            else if (rand_num == 2)
            {
                base1 += 'G';
                base2 += 'C';
            }
            else
            {

                base1 += 'C';
                base2 += 'G';
            }
        }

        DNA_Sample sampleN = {
            "random spc " + to_string(i),
            10000,
            (char *)base1.c_str(),
            (char *)base2.c_str(),
        };

        catalog.push_back(sampleN);
    }
}

int main()
{

    // initilizing sample data
    cout << "initlizing demo data \n";
    populateCatalog();
    DNA_Sample sampleToTest = {
        "test sample",
        9608,
        (char *)"",
        (char *)"",
    };

    const int catalogSampleLengths = 10000;

    string paddStart = "";
    string paddEnd = "";

    for (int i = 0; i < catalogSampleLengths - sampleToTest.length; i++)
    {
        paddStart += " ";
    }

    cout << "starting calculations... \n";
    // performing computation
    clock_t simd_start = clock();
    vector<float> resultsBest(catalog.size(), 0.0f);

    for (int i = 0; i < catalogSampleLengths - sampleToTest.length; i++)
    {
        // pads

        string paddedBp1 = (paddStart + sampleToTest.bp1 + paddEnd);
        string paddedBp2 = (paddStart + sampleToTest.bp2 + paddEnd);

        DNA_Sample sampleToTestPadded = {
            "test sample padded",
            (int)paddStart.length() + sampleToTest.length,
            (char *)paddedBp1.c_str(),
            (char *)paddedBp2.c_str(),
        };

        vector<float> res = matchCheck(sampleToTestPadded, paddStart.length());

        for (int j = 0; j < res.size(); j++)
        {
            if (res[j] > resultsBest[j])
                resultsBest[j] = res[j];
        }

        paddStart.pop_back();
        paddEnd.push_back(' ');
    }

    clock_t simd_end = clock();
    double simd_time = 0.0;
    simd_time = simd_time + (double)(simd_end - simd_start);
    simd_time = simd_time / CLOCKS_PER_SEC;

    float bestmatch = 0;
    for (int j = 0; j < resultsBest.size(); j++)
    {
        if (resultsBest[j] > resultsBest[bestmatch])
            bestmatch = j;
    }

    cout << "\n\nBest match: " << catalog[bestmatch].name << " : " << resultsBest[bestmatch] * 100 << "% match\n";

    cout << "\n\ncalculations finished in " << simd_time << " sec" << '\n';
}
